Функция ОстатокТовара(Номенклатура, Склад) Экспорт
    Запрос = Новый Запрос;
    Запрос.Текст =
    "ВЫБРАТЬ
    |   ОстаткиТоваров.КоличествоОстаток КАК Остаток
    |ИЗ
    |   РегистрНакопления.ТоварыНаСкладах.Остатки(, Номенклатура = &Номенклатура И Склад = &Склад) КАК ОстаткиТоваров";
    Запрос.УстановитьПараметр("Номенклатура", Номенклатура);
    Запрос.УстановитьПараметр("Склад", Склад);
    Выборка = Запрос.Выбрать();
    Если Выборка.Следующий() Тогда
        Возврат Выборка.Остаток;
    КонецЕсли;
    Возврат 0;
КонецФункции

Функция СуммаПродаж(Номенклатура, НачалоПериода, КонецПериода) Экспорт
    Запрос = Новый Запрос;
    Запрос.Текст =
    "ВЫБРАТЬ
    |   ПродажиОбороты.СуммаОборот КАК Сумма
    |ИЗ
    |   РегистрНакопления.Продажи.Обороты(&НачалоПериода, &КонецПериода, , Номенклатура = &Номенклатура) КАК ПродажиОбороты";
    Запрос.УстановитьПараметр("Номенклатура", Номенклатура);
    Запрос.УстановитьПараметр("НачалоПериода", НачалоПериода);
    Запрос.УстановитьПараметр("КонецПериода", КонецПериода);
    Выборка = Запрос.Выбрать();
    Если Выборка.Следующий() Тогда
        Возврат Выборка.Сумма;
    КонецЕсли;
    Возврат 0;
КонецФункции

Функция ТекущаяЦена(Номенклатура, НаДату) Экспорт
