КонецФункции

Функция СуммаДокумента(ДокументСсылка) Экспорт
    Запрос = Новый Запрос;
    Запрос.Текст =
    "ВЫБРАТЬ
    |   СУММА(ТоварыРасход.Сумма) КАК Итого
    |ИЗ
    |   Документ.РасходТовара.Товары КАК ТоварыРасход
    |ГДЕ
    |   ТоварыРасход.Ссылка = &Ссылка";
    Запрос.УстановитьПараметр("Ссылка", ДокументСсылка);
    Выборка = Запрос.Выбрать();
    Если Выборка.Следующий() Тогда
        Возврат ?(Выборка.Итого = NULL, 0, Выборка.Итого);
    КонецЕсли;
    Возврат 0;
КонецФункции

