Функция НайтиИлиСоздать(Наименование) Экспорт
    Ссылка = Справочники.Контрагенты.НайтиПоНаименованию(Наименование);
    Если Ссылка.Пустая() Тогда
        Элемент = Справочники.Контрагенты.СоздатьЭлемент();
        Элемент.Наименование = Наименование;
        Элемент.Записать();
        Ссылка = Элемент.Ссылка;
    КонецЕсли;
    Возврат Ссылка;
КонецФункции

