Процедура КонтрольОстатков(Отказ, Склад)
    Запрос = Новый Запрос;
    Запрос.Текст =
    "ВЫБРАТЬ
    |   ОстаткиТоваров.Номенклатура КАК Номенклатура,
    |   ОстаткиТоваров.КоличествоОстаток КАК Остаток
    |ИЗ
    |   РегистрНакопления.ТоварыНаСкладах.Остатки(, Склад = &Склад) КАК ОстаткиТоваров
    |ГДЕ
    |   ОстаткиТоваров.КоличествоОстаток < 0";
    Запрос.УстановитьПараметр("Склад", Склад);
    Выборка = Запрос.Выбрать();
    Пока Выборка.Следующий() Цикл
        Отказ = Истина;
        Сообщить("Отрицательный остаток: " + Выборка.Номенклатура);
    КонецЦикла;
КонецПроцедуры

Процедура СписатьТовар(Номенклатура, Склад, Количество, Регистратор) Экспорт
    НаборЗаписей = РегистрыНакопления.ТоварыНаСкладах.СоздатьНаборЗаписей();
    НаборЗаписей.Отбор.Регистратор.Установить(Регистратор);
    Движение = НаборЗаписей.Добавить();
    Движение.ВидДвижения = ВидДвиженияНакопления.Расход;
    Движение.Период = ТекущаяСеансаДата();
    Движение.Номенклатура = Номенклатура;
    Движение.Склад = Склад;
    Движение.Количество = Количество;
    НаборЗаписей.Записать(Ложь);
КонецПроцедуры

